s\" v-bind:dataid=\"data.row[primaryKeyforModule]\" dataController=\"COMPANYSETUP_UPDATE\" \r\n                        v-bind:statuslist=\"StatusListForListing\" v-bind:item=\"data.row[primaryKeyforModule]\" data-action=\"index\" :module=moduleCode :subModule=subModuleCode\r\n                        v-bind:dataselected=\"data.row.is_active == 'ACTIVE' ? 'Active' : 'Inactive'\"\r\n                        v-bind:title =\"data.row.is_active == 'ACTIVE' ? 'Active' : 'Inactive'\"\r\n                        v-bind:callbackfunction=\"FetchData\" v-bind:isselectedvaluestring=\"true\">\r\n                    </listing-status>\r\n                </template>\r\n                \r\n                <template v-if=\"data.column.COLUMN_NAME == 'is_active' && (moduleCode == 'Company' && subModuleCode == 'Status')\">                          \r\n                    <listing-status :isfor=\"'COMPANYSETUP_UPDATE'\" v-if=\"isCRMShowStausDrop(data.row.is_active, 'COMPANYSETUP_UPDATE') && data.row.company_id > 0\"\r\n                         ref=\"updatestatus\" v-bind:dataid=\"data.row[primaryKeyforModule]\" dataController=\"COMPANYSETUP_UPDATE\" \r\n                        v-bind:statuslist=\"StatusListForListing\" v-bind:item=\"data.row[primaryKeyforModule]\" data-action=\"index\" :module=moduleCode :subModule=subModuleCode\r\n                        v-bind:dataselected=\"data.row.is_active == 'ACTIVE' ? 'Active' : 'Inactive'\"\r\n                        v-bind:title =\"data.row.is_active == 'ACTIVE' ? 'Active' : 'Inactive'\"\r\n                        v-bind:callbackfunction=\"FetchData\" v-bind:isselectedvaluestring=\"true\">\r\n                    </listing-status>\r\n\r\n                    <span v-bind:class=\"getStatusClassList((data.row.is_active), 'is_active')\" v-else>\r\n                        {{ (data.row.is_active.toLowerCase() == 'active' ? 'Active' : 'Inactive') }}\r\n                    </span>\r\n                </template>\r\n               \r\n                \r\n            </template>\r\n        </tg-list> \r\n        <AddCompanySetup :recordId=\"recordId\" :title=\"$t('Manage ') + $t(subModuleCode)\" v-if=\"showAddPopup\" :refId=\"refId\" v-on:close=\"showAddPopup=false;recordId=0\" v-on:addReloadData=\"FetchData(); showAddPopup=false;recordId=0\" v-bind:moduleName=moduleCode v-bind:emitName=\"'addReloadData'\" v-bind:addApiUrl=addAPIUrl v-bind:subModule=subModuleCode v-bind:addUserGuide=addUserGuide />\r\n\r\n    </div>\r\n</template>\r\n<script>\r\nimport CompanyDataService from \"@/services/DataService\";\r\n// import Schema from \"@/views/Company/Break/BreakSchema\";\r\nimport AddCompanySetup from \"@/components/Modals/AddCompanySetup.vue\";\r\nimport Vue from \"vue\";\r\nimport moment from 'moment'\r\nexport default {\r\n    components: {   \r\n        AddCompanySetup,\r\n    },\r\n    props: {\r\n        sourcetype: {\r\n            type: String,\r\n            required: true\r\n        },\r\n        moduleCode:{\r\n            type: String,\r\n            required: true\r\n        },\r\n        subModuleCode:{\r\n            type: String,\r\n            required: true\r\n        },\r\n        primaryKeyforModule:{\r\n            type: String,\r\n            required: true\r\n        },\r\n        addAPIUrl:{\r\n            type: String,\r\n            required: true\r\n        },\r\n        ActionColunName:{\r\n            type: String,\r\n            required: true\r\n        },\r\n        addUserGuide:{\r\n            type: String            \r\n        }\r\n    },\r\n    data() {\r\n        return {\r\n            recordId:0,\r\n            showAddPopup:false,\r\n            noRecord:false,\r\n            isLoading: false,\r\n            CompanyId: null,\r\n            ListingData: [],\r\n            TotalRecords: 0,\r\n            //listheaderbuttons: Schema.buttons,\r\n            ShowManageView: false,\r\n            ShowAddCustomReportView: false,\r\n            PageSize: 10,\r\n            PageNumber: 1,\r\n            isPaged: 1,\r\n            TotalPages: 0,\r\n            //listActions: Schema.listActions,\r\n            searchCondition: '',\r\n            conditionForInstantSearch: \"\",\r\n            SortBy: '',\r\n            SortExp: '',\r\n            showsharereportview: false,\r\n            showemailreportview: false,\r\n            showschedulereportview: false,\r\n            // ReportID: null,\r\n            // reportname: '',\r\n            // reportid: '',\r\n            foldername: '',\r\n            folderid: '',\r\n            LeadStatusList: [],\r\n            // MODULENAME: null,\r\n            // SUBMODULECODE: null,\r\n            PrimaryKeyId: null,\r\n            privilegeParams: null,\r\n            //addAPIUrl: '',\r\n            sharetype: '',\r\n            Headers: [],\r\n            filteredHeaders: [],\r\n            FormSchema: [],\r\n            StatusListForListing: [\r\n                { \r\n                    STATUS: 'Active', \r\n                    STATUS_ID: 1001, \r\n                    STATUS_COLOR: \"#ffffff\", \r\n                    STATUS_BG_COLOR: \"#28a745\" \r\n                },{ \r\n                    STATUS: 'Inactive', \r\n                    STATUS_ID: 1002, \r\n                    STATUS_COLOR: \"#ffffff\", \r\n                    STATUS_BG_COLOR: \"#d72435\"\r\n                }\r\n            ],\r\n            Buttons:[\r\n                {\r\n                    title: this.$t('Add'),\r\n                    iconClass: 'fa-plus',\r\n                    callbackfunction: 'AddScreenPopup',\r\n                    additionalClass: '',\r\n                    isdisabled: false,\r\n                    isvisible: true,\r\n                    checkPrivilege: true\r\n                }, {\r\n                    id: 'ActiveMultiple',\r\n                    title: this.$t('Active'),\r\n                    iconClass: 'fa-check',\r\n                    callbackfunction: 'ActiveMultipleListing',\r\n                    additionalClass: '',\r\n                    isdisabled: true,\r\n                    isvisible: true,\r\n                    checkPrivilege: true,\r\n                    isEnabledOnSelectedRow: true\r\n                }, {\r\n                    id: 'InactiveMultiple',\r\n                    title: this.$t('Inactive'),\r\n                    iconClass: 'fa-close',\r\n                    callbackfunction: 'InactiveMultipleListing',\r\n                    additionalClass: '',\r\n                    isdisabled: true,\r\n                    isvisible: true,\r\n                    checkPrivilege: true,\r\n                    isEnabledOnSelectedRow: true\r\n                }, {\r\n                    id: 'DeleteMultiple',\r\n                    title: this.$t('Delete'),\r\n                    iconClass: 'fa-trash-o',\r\n                    callbackfunction: 'commonDeleteData',\r\n                    isdisabled: true,\r\n                    isvisible: true,\r\n                    isEnabledOnSelectedRow: true\r\n                }    \r\n            ],\r\n            topsearchField : [\r\n                {\r\n                    fieldName: 'Search  ' ,\r\n                    fieldType: \"text\",\r\n                    // fieldIcon: \"fa-file\",\r\n                    fieldSearchConditionName: '',\r\n                    isSearch: true,\r\n                    value: \"\",\r\n                    listOptions: []\r\n                },\r\n            ],\r\n            refId: null\r\n        }\r\n    },\r\n    async created() {\r\n        var ths = this;\r\n       // debugger\r\n        ths.CompanyId = ths.GetUserInfo.CompanyId;\r\n        ths.privilegeParams = `controller=Break&action=`;\r\n        await ths.FetchData();\r\n        // Schema.bindleftCommonSearchdropdown(ths, 'Dynamic_Reporting', 'FOLDER_NAME')\r\n        // Schema.bindleftCommonSearchdropdown(ths, 'Dynamic_Reporting', 'CREATED_BY')\r\n        // Schema.bindleftCommonSearchdropdown(ths, 'Dynamic_Reporting', 'MODIFIED_BY')\r\n         ths.getStatuslistForListing(\"Dynamic_Reporting\", \"en\");\r\n    },\r\n    computed: {\r\n        filteredUserData() {\r\n            return this.vueObj.UserData.map((item) => {\r\n            const filteredItem = { ...item };\r\n\r\n            // Check if USER_EMP_ID is null or empty, then replace with '--'\r\n            if (filteredItem.USER_EMP_ID === null || filteredItem.USER_EMP_ID === '') {\r\n                filteredItem.USER_EMP_ID = '--';\r\n            }\r\n\r\n            return filteredItem;\r\n            });\r\n        },\r\n        \r\n    },\r\n    mounted() {\r\n        var ths = this;\r\n        ths.topsearchField.forEach(item => {\r\n            item.value = '';\r\n            item.isSearch = false;\r\n        })\r\n    },\r\n\r\n    updated(){\r\n        const divElement = document.getElementsByClassName('theme-primary partition p-actions-expand')\r\n        if (divElement[0] && divElement[0].lastChild.className != 'p-name text-white' ) {\r\n            const spanElement = document.createElement('span')\r\n            spanElement.className = \"p-name text-white\"\r\n            if(this.subModuleCode ==='PerformanceReview'){\r\n                spanElement.textContent =  this.$t('ReviewTemplate');\r\n            }\r\n            else\r\n            {\r\n                spanElement.textContent = this.$t(this.subModuleCode);\r\n            }\r\n            divElement[0].appendChild(spanElement);\r\n        }\r\n    },\r\n\r\n    methods: {\r\n        getStatusClassList: function (status) {\r\n            var returnClass = '';\r\n            status = status.toLowerCase();\r\n            switch (status) {\r\n                case 'active':\r\n                    returnClass = 'px-2 text-center text-white d-block bg-success';\r\n                    break;\r\n                case 'inactive':\r\n                    returnClass = 'px-2 text-center text-white d-block bg-danger';\r\n                    break;\r\n                default:\r\n                    returnClass = '';\r\n            }\r\n            return returnClass;\r\n        },\r\n        getStatus: function(obj){\r\n            try {\r\n                const statusIdObj = JSON.parse(obj);\r\n                return statusIdObj.value;\r\n            } \r\n            catch (error) {\r\n                console.error('Error parsing status_id:', error);\r\n                return obj;\r\n            }\r\n        },\r\n\r\n        formatTime(time) {\r\n            if (time) {\r\n                return moment(time).format('hh:mm A');\r\n            } else {\r\n                return '--';\r\n            }\r\n        },\r\n\r\n        AddChildLocation: function (id) {\r\n            debugger\r\n            var ths = this;\r\n            ths.moduleCode='Company'\r\n            ths.subModuleCode='Location';\r\n            if (id == undefined) {\r\n                id = 0;\r\n            }\r\n            ths.refId = id;\r\n            ths.showAddPopup = true;\r\n        },\r\n        renderActions: function (row) {\r\n            console.log(row);\r\n            // var self = this;\r\n            // let rtnActionArray = [];\r\n            // self.listActions.forEach(actionItem => {\r\n            //     let action = { ...actionItem };\r\n            //     switch (action.title) {\r\n            //         case 'View':\r\n            //             action.isVisible = row.ACCESS != null ? true : true;\r\n            //             break;\r\n            //         case 'Send Email':\r\n            //             action.isVisible = row.ACCESS != 1 && row.ACCESS != 2 ? true : false;\r\n            //             break;\r\n            //         case 'Schedule':\r\n            //             action.isVisible = row.ACCESS != 1 && row.ACCESS != 2 ? true : false;\r\n            //             break;\r\n            //         case 'Share':\r\n            //             action.isVisible = row.ACCESS != 1 && row.ACCESS != 2 ? true : false;\r\n            //             break;\r\n            //         case 'Edit':\r\n            //             action.isVisible = row.ACCESS != 1 ? true : false;\r\n            //             break;\r\n            //         default:\r\n            //             action.isVisible = true;\r\n            //             break;\r\n            //     }\r\n            //     rtnActionArray.push(action);\r\n            // });\r\n            // return rtnActionArray;\r\n            return [];\r\n        },\r\n        \r\n        commonHeaderButtonClick: function (event) {\r\n            switch (event.callbackfunction) {\r\n                case \"commonDeleteData\":\r\n                    this.commonDeleteData();\r\n                    break;\r\n\r\n                case \"ActiveMultipleListing\":\r\n                console.log(\"Active\");\r\n                    this.UpdateStatus(\"Active\");\r\n                    break;\r\n\r\n                case \"InactiveMultipleListing\":\r\n                console.log(\"Inactive\");\r\n                    this.UpdateStatus(\"Inactive\");\r\n                    break;\r\n\r\n                case \"AddScreenPopup\":\r\n                    this.showAddPopup = true\r\n                    break;\r\n            }\r\n        },\r\n        // actionButtonClick: function (callbackfunction, item, index, event) {\r\n        //     var vm = this;\r\n        //     switch (callbackfunction) {\r\n                \r\n        //         case 'Update':\r\n        //             this.UpdateStatus(item);\r\n        //             break;\r\n\r\n        //         case 'sendemail':\r\n        //             vm.sendemail(item.REPORT_ID, item.MODULENAME, item.SUBMODULECODE);\r\n        //             break;\r\n        //         case 'editreport':\r\n        //             vm.editreport(item);\r\n        //             break;\r\n        //         case 'setschedule':\r\n        //             vm.setschedule(item.REPORT_ID);\r\n        //             break;\r\n        //         case 'ViewReport':\r\n        //             vm.ViewReport(item.REPORT_ID, item.ACCESS, item.FOLDER_ID);\r\n        //             break;\r\n        //     }\r\n        // },\r\n        // editreport: function (data) {\r\n        //     var vm = this;\r\n        //     CompanyDataService.CheckPrivilege(vm.privilegeParams+'Update').then((response)=>{\r\n        //         if(response.data){\r\n        //             vm.$router.push({\r\n        //                 name: 'EditDataReport',\r\n        //                 params: {\r\n        //                     Modulename: data.MODULENAME, Submodulecode: data.SUBMODULECODE, ReportName: data.REPORTNAME, ReportID: data.REPORT_ID,\r\n        //                     Module_Id: data.MODULE_ID, Folder_Id: data.FOLDER_ID, Sub_Module_Id: data.Sub_Module_Id, Version: vm.Version, Action: 'Edit'\r\n        //                 }\r\n        //             });\r\n        //         }\r\n        //         else{\r\n        //             vm.ShowAlert(vm.$t('UnAuthorized'), \"warning\", true, \"Alert\");\r\n        //             return false;\r\n        //         }\r\n        //     });\r\n        // },\r\n        // ViewReport: function (ReportID, ACCESS, FolderID) {\r\n        //     var vm = this;\r\n        //     vm.$router.push('/Report/viewcustomreport/' + btoa(JSON.stringify({ ReportID: ReportID, ACCESS: ACCESS , Folder_Id: FolderID })))\r\n\r\n        // },\r\n        sortdata: async function (s) {\r\n            var SortDir = \"sort tb_headerSortDown\";\r\n            this.SortBy = s;\r\n            if (s === this.SortBy) {\r\n                if (this.SortExp == \"\") {\r\n                    this.SortExp = \"ASC\";\r\n                    SortDir = \"sort tb_headerSortDown\";\r\n                }\r\n                else if (this.SortExp == \"ASC\") {\r\n                    this.SortExp = \"DESC\";\r\n                    SortDir = \"sort tb_headerSortUp\";\r\n                }\r\n                else {\r\n                    this.SortExp = \"ASC\";\r\n                    SortDir = \"sort tb_headerSortDown\";\r\n                }\r\n            }\r\n\r\n            await this.FetchData();\r\n            $(\"#th-\" + s + '  span:first-child').attr(\"class\", SortDir);\r\n        },\r\n        pagerMethod: async function (value) {\r\n            this.PageSize = value.PageSize;\r\n            this.PageNumber = value.PageNumber;\r\n            await this.FetchData();\r\n        },\r\n        leftCommonSearch: async function (value) {\r\n            var vm = this;\r\n            console.log(vm.searchCondition);\r\n            this.PageNumber = value.PageNumber;\r\n            this.isPaged = 1;\r\n            if (typeof value.searchCondition != 'undefined') {\r\n                this.searchCondition = value.searchCondition;\r\n            }\r\n            else {\r\n                this.searchCondition = \"\";\r\n            }\r\n\r\n            await this.FetchData();\r\n        },\r\n        // ManageFolder: function () {\r\n        //     var vm = this;\r\n        //     CompanyDataService.CheckPrivilege(vm.privilegeParams+'FolderListing').then((response)=>{\r\n        //         if(response.data){\r\n        //             vm.ShowManageView = true;\r\n        //             $(\"#modalManageView\").modal('show');\r\n        //             setTimeout(function () {\r\n        //                 $(\"#modalManageView\").modal('show');\r\n        //                 setTimeout(function () {\r\n        //                     vm.SetBootstraptoolTip();\r\n        //                 }, 200);\r\n        //             }, 1000);\r\n        //             vm.$refs.managefolder?.GetViewList();\r\n        //         }\r\n        //         else{\r\n        //             vm.ShowAlert(vm.$t('UnAuthorized'), \"warning\", true, \"Alert\");\r\n        //             return false;\r\n        //         }\r\n        //     });\r\n        // },\r\n        \r\n        commonDeleteData: function (event) {\r\n            var vm = this;\r\n            // CompanyDataService.CheckPrivilege(vm.privilegeParams+'Delete').then((response)=>{\r\n            //     if(response.data){\r\n                    var val = \"\";\r\n                    $('.chkItems:checkbox:checked').not(\"[id^='chkAll_0']\").each(function () {\r\n                        if (val.length > 0)\r\n                            val += ',';\r\n                        val += $(this).val();\r\n                    });\r\n                    if (val.length > 0) {\r\n                        if(this.subModuleCode=='Location' && this.moduleCode=='Company')\r\n                        {\r\n                            vm.confirmR(vm.$t(\"ConfirmDeleteLocation\"), true, (vm.$t(\"Delete\") + \"  \" + vm.$t(\"Report\")), function () {\r\n                            var postJSON = {\r\n                                IDS: val,\r\n                                moduleName: vm.moduleCode,\r\n                                subModuleCode: vm.subModuleCode,\r\n                                refCode: \"COMPANYSETUP_DELETE\"\r\n                            };\r\n                            var objectPostString = JSON.stringify(postJSON);\r\n                            CompanyDataService.DeleteLocation(objectPostString).then(async function (response) {\r\n                                if (response.data.code == '1') {\r\n                                    $('.chkItems:checkbox:checked,#chkAll_0').prop(\"checked\", false).removeAttr('checked');\r\n                                    $(\"#DeleteMultiple\").addClass(\"disabled\");\r\n                                        vm.ShowAlert(vm.$t('DeletedSuccess',true,[vm.subModuleCode ]), 'success', true, vm.$t('Alert'));\r\n                                    vm.PageNumber = parseInt(vm.PageNumber) - 1;\r\n                                    if (vm.PageNumber <= 0) {\r\n                                        vm.PageNumber = 1;\r\n                                    }\r\n                                    await vm.FetchData();\r\n                                }\r\n                                else {\r\n                                    vm.ShowAlert(vm.$t('DeletedError',true,[vm.subModuleCode ]), 'failure', true, vm.$t('Alert'));\r\n                                   \r\n                                }\r\n\r\n                            },);\r\n                        });\r\n                         \r\n                        }else{\r\n                            vm.confirmR(vm.$t(\"ConfirmDelete\"), true, (vm.$t(\"Delete\") + \"  \" + vm.$t(\"Report\")), function () {\r\n                                var postJSON = {\r\n                                    ids: val,\r\n                                    moduleName: vm.moduleCode,\r\n                                    subModuleCode: vm.subModuleCode,\r\n                                    refCode: \"COMPANYSETUP_DELETE\"\r\n                                };\r\n                                var objectPostString = JSON.stringify(postJSON);\r\n                                CompanyDataService.CommonDeleteData(objectPostString).then(async function (response) {\r\n                                    if (response.status == 200) {\r\n                                        $('.chkItems:checkbox:checked,#chkAll_0').prop(\"checked\", false).removeAttr('checked');\r\n                                        $(\"#DeleteMultiple\").addClass(\"disabled\");\r\n                                        // if(vm.moduleCode == \"Appointment\" && vm.subModuleCode == \"Service\")\r\n                                        // {\r\n                                            vm.ShowAlert(vm.$t('DeletedSuccess',true,[vm.subModuleCode ]), 'success', true, vm.$t('Alert'));\r\n                                        // }\r\n                                        // else\r\n                                        // {\r\n                                        //     vm.ShowAlert(vm.$t('DeletedSuccessfully', [vm.$t('Records')]), \"success\", true, vm.$t(\"Alert\"));\r\n                                        // }\r\n                                        \r\n                                        vm.PageNumber = parseInt(vm.PageNumber) - 1;\r\n                                        if (vm.PageNumber <= 0) {\r\n                                            vm.PageNumber = 1;\r\n                                        }\r\n                                        await vm.FetchData();\r\n                                    }\r\n                                    else {\r\n                                        // if(vm.moduleCode == \"Appointment\" && vm.subModuleCode == \"Service\")\r\n                                        // {\r\n                                            vm.ShowAlert(vm.$t('DeletedError',true,[vm.subModuleCode ]), 'failure', true, vm.$t('Alert'));\r\n                                        // }\r\n                                        // else\r\n                                        // {\r\n                                        //     vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Records')]), \"failure\", true, vm.$t(\"Alert\"));\r\n                                        // }\r\n                                    \r\n                                    }\r\n\r\n                                },);\r\n                            });\r\n                        }\r\n                    }\r\n                    else {\r\n                        vm.ShowAlert(vm.$t(\"Selectanyrecordtodelete\"));\r\n                    }\r\n            //     }\r\n            //     else\r\n            //     {\r\n            //         vm.ShowAlert(vm.$t('UnAuthorized'), \"warning\", true, \"Alert\");\r\n            //         return false;\r\n            //     }\r\n            // })\r\n        },\r\n        UpdateStatus: async function (status) {          \r\n            var vm = this;\r\n            if (status == 'Active') {\r\n                status = 1001;\r\n            }\r\n           else {\r\n                status = 1002;\r\n            }\r\n            var val = \"\";\r\n            $('.chkItems:checkbox:checked').not(\"[id^='chkAll_0']\").each(function () {\r\n                if (val.length > 0) {\r\n                    val += ',';\r\n                }\r\n                val += $(this).val();\r\n            });\r\n            \r\n            if (val.length > 0) {\r\n                vm.Buttons[1].isdisabled=false;\r\n                vm.Buttons[2].isdisabled=false;\r\n                vm.Buttons[3].isdisabled=false;\r\n                vm.confirmR(vm.$t(\"AreYouSureToUpdateStatus\"), true, (vm.$t(\"update\") + \"  \" + vm.$t(\"status\")), function () {\r\n                    // Send IDs as a comma-separated string\r\n                    var postJSON = {\r\n                        ID: val,\r\n                        StatusId: status,\r\n                        IsFor: \"COMPANYSETUP_UPDATE\",\r\n                        Module: vm.moduleCode,\r\n                        Submodule: vm.subModuleCode,\r\n                    };\r\n\r\n                    var objectPostString = JSON.stringify(postJSON);\r\n                    CompanyDataService.CommonUpdateStatus(objectPostString).then(response => {\r\n                        if (response.status == 200) {\r\n                            $('.chkItems:checkbox:checked').prop(\"checked\", false).removeAttr('checked');\r\n                            vm.Buttons[1].isdisabled=true;\r\n                            vm.Buttons[2].isdisabled=true;\r\n                            vm.Buttons[3].isdisabled=true;\r\n                            \r\n                            vm.ShowAlert(vm.$t('UpdatedSuccess',true,[vm.subModuleCode ]), 'success', true, vm.$t('Alert'));\r\n                            // vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), \"success\", true, vm.$t(\"Alert\"));\r\n                            vm.FetchData();\r\n                        }\r\n                    });\r\n                });\r\n            }\r\n        },\r\n        getRequestParams: function (pageNumber, pageSize, sortBy, sortExp, isPaged, searchcondition) {\r\n            let params = {};\r\n            if (pageNumber) { params[\"pageNumber\"] = pageNumber; }\r\n            if (searchcondition) { params[\"searchcondition\"] = searchcondition; }\r\n            if (isPaged) { params[\"is_paged\"] = isPaged; }\r\n            if (sortBy) { params[\"sortBy\"] = sortBy; }\r\n            if (sortExp) { params[\"sortExp\"] = sortExp; }\r\n            if (pageSize) { params[\"pageSize\"] = pageSize; }\r\n            return params;\r\n        },\r\n        clickEventOfColumn: function (row, column) {\r\n            // console.log(\"row\",row,column.COLUMN_NAME)\r\n            var vueObj  = this;\r\n             if( column.DISPLAY_NAME==\"Shift Name\"){\r\n                vueObj.moduleCode='Company'\r\n             }\r\n            if (column.COLUMN_NAME == 'title' && vueObj.moduleCode == \"AnnouncementMessage\") {\r\n                this.recordId = row.id\r\n                this.showAddPopup = true\r\n            }\r\n\r\n            else if (column.COLUMN_NAME == 'title' && vueObj.moduleCode == \"Review\") {\r\n                this.recordId = row.review_template_id \r\n                this.showAddPopup = true\r\n            }\r\n            else if (column.COLUMN_NAME == 'title' && vueObj.subModuleCode == \"Question\") {              \r\n                this.recordId = row.question_bank_id \r\n                this.showAddPopup = true\r\n            }\r\n\r\n            else if (column.COLUMN_NAME == 'title' && vueObj.moduleCode == \"Skill\") {\r\n                this.recordId = row.skill_id \r\n                this.showAddPopup = true\r\n            }\r\n\r\n            else if (column.COLUMN_NAME == 'stage_name' && vueObj.moduleCode == \"Stage\") {                \r\n                this.recordId = row.stage_id \r\n                this.showAddPopup = true\r\n            }\r\n\r\n      