 class=\"col-lg-12\" >\r\n                                    <div class=\"col-lg-12 bg-light px-2 pt-2 border mb-3\" v-for=\"(citem,cindex) in item.ItemData\" :key=\"cindex\">\r\n                                        <div class=\"row\">\r\n                                            <div class=\"col-lg-3\">\r\n                                                <div class=\"form-group mb-0\">\r\n                                                    <label>{{ $t('Title') }}:<span class=\"text-danger\">*</span></label>\r\n                                                    <input type=\"text\" class=\"form-control\" v-model=\"citem.Title\" :class=\"{'is-invalid':citem.IsItemChcek==true}\" @input=\"CheckItemSetion(citem)\"/>\r\n                                                    <span name=\"Subject\" class=\"invalid-feedback\" v-if=\"citem.IsItemChcek\">{{$t('ItemTitleRequired')}}.</span>\r\n                                                </div>\r\n                                            </div>\r\n                                            <div class=\"col-lg-3\">\r\n                                                <div class=\"form-group\">\r\n                                                    <label>{{$t('AnswerType')}}:<span class=\"text-danger\">* </span></label>\r\n                                                    <select name=\"Status\" class=\"form-control w-100\" v-model=\"citem.AnswerType\" @change=\"onAnswerTypeChange(citem)\" :class=\"{'is-invalid':citem.IsitemAsnwwr==true}\">\r\n                                                        <option value=\"\" selected=\"selected\">{{ $t('SelectAnswerType') }}</option>\r\n                                                        <option :value=\"item.value\" v-for=\"(item,index) in AnswerTypeData\" :key=\"index\">{{item.name}} </option>                                                        \r\n                                                    </select>\r\n                                                    <span name=\"Subject\" class=\"invalid-feedback\" v-if=\"citem.IsitemAsnwwr\">{{$t('AnswerTypeRequired')}}.</span>\r\n                                                </div>\r\n                                            </div>\r\n                                            <div class=\"col-lg-5\">\r\n                                                <div class=\"form-group\">\r\n                                                    <label>{{ $t('AnswerOption') }}</label>                                                    \r\n                                                    <div v-if=\"citem.AnswerType==''\">--</div>\r\n                                                    <div v-else-if=\"citem.AnswerType=='StarRating'\">{{$t('WillShowRating')}}.</div>\r\n                                                    <div v-else-if=\"citem.AnswerType=='MarkAsDone'\">{{$t('YouCanMark')}}.</div>\r\n                                                    <div v-else-if=\"citem.AnswerType=='TextBox'\">{{$t('WillShowText')}}.</div>\r\n                                                    <input v-else type=\"text\" class=\"form-control\" v-model=\"citem.AnswerOption\" />\r\n                                                </div>\r\n                                            </div>\r\n                                            <div class=\"col-lg-1 p-0\">\r\n                                                <div class=\"form-group mt-4 text-center\">\r\n                                                    <a href=\"javascript:;\" v-if=\"cindex==0\"  @click=\"addChild(item, cindex)\"><em class=\"round-icon-small fa fa-plus bg-success float-none\"></em></a>\r\n                                                    <a href=\"javascript:;\" @click=\"deleteItem(item, cindex)\" v-if=\"cindex>0\"><em class=\"round-icon-small fa fa-trash bg-danger float-none\"></em></a>\r\n                                                </div>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                        </div>\r\n                        <div class=\"row flex-row-reverse mt-3 mb-3\">\r\n                                <div class=\"col-lg-6 text-right\">\r\n                                    <a href=\"javascript:;\" title=\"Save\" class=\"btn btn-info mr-2\" @click=\"ShowCheckListPreview\">\r\n                                        <i class=\"fa fa-eye pr-2\"></i>{{ $t('Preview') }} </a>\r\n                                        <a href=\"javascript:;\" title=\"Save\" class=\"btn btn-success save-btn mr-2\" @click=\"OnSubmit\">\r\n                                <i class=\"fa fa-save pr-2\"></i>{{ $t('Save') }}</a>\r\n                                <a href=\"javascript:;\" title=\"Cancel\" class=\"btn btn-danger mr-2\" @click=\"CloseCheckList\">\r\n                                    <i class=\"fa fa-close pr-2\"></i>{{$t('Cancel')}} </a>\r\n                                </div>\r\n                                <div class=\"col-lg-6\">\r\n                                    <div class=\"py-2\"><span class=\"mandatory\">{{$t('MandatoryString')}}.</span></div></div>\r\n                        </div>\r\n                    </div> \r\n                </div>\r\n            </div>\r\n        </div>\r\n        <CheckListPreview v-if=\"isCheckListPreview\" :SectionData=\"SectionData\"></CheckListPreview>\r\n    </div>\r\n</template>\r\n<script>\r\nimport DataService from '../../../services/DataService'\r\nimport CheckListPreview from './CheckListPreview.vue';\r\nexport default {\r\n    components:{CheckListPreview},\r\n    props:{\r\n        CheckListId:{\r\n            type:Number,\r\n            required:true\r\n        }\r\n    },\r\n    data(){\r\n        return{\r\n            isLoading:false,\r\n            buttons:[],\r\n            FormSchema: [               \r\n                {\r\n                    layoutType: \"triple\",\r\n                    Data: [\r\n                    {\r\n                            astype: \"TextField\",                                                \r\n                            label: this.$t('CheckListTitle'),\r\n                            name: \"Subject\",\r\n                            value: \"\",               \r\n                            placeholder: this.$t('Enter Check List Title'),\r\n                            validationRules: { \"required\": true, max: 100 },\r\n                        },\r\n                        {\r\n                            astype: \"SelectField\",                                                \r\n                            label: this.$t('moduleName'),\r\n                            name: \"IssueType\",\r\n                            value: \"\",  \r\n                            config: {\r\n                                options: []\r\n                            },                           \r\n                            placeholder: this.$t('moduleName'),\r\n                            validationRules: { \"required\": true, max: 100 },\r\n                        },\r\n                        {\r\n                            astype: \"SelectField\",                                                \r\n                            label: this.$t('Status'),\r\n                            name: \"Status\",\r\n                            value: \"1001\",  \r\n                            config: {\r\n                                options: []\r\n                            },                           \r\n                            placeholder: this.$t('Select Status'),\r\n                            validationRules: { \"required\": true, max: 100 },\r\n                        },\r\n                        {\r\n                            astype: \"SelectField\",                                                \r\n                            label: this.$t('IndustryType'),\r\n                            name: \"IndustryType\",\r\n                            value: \"\",  \r\n                            config: {\r\n                                options: []\r\n                            },                           \r\n                            placeholder: this.$t('Select Industry Type'),\r\n                            validationRules: { \"required\": true, max: 100 },\r\n                        }                                                             \r\n                    ]\r\n                },              \r\n                {\r\n                    layoutType: \"single\",\r\n                    Data: [\r\n                        {\r\n                            astype: \"TextAreaField\",                 \r\n                            label: this.$t('DESCRIPTION'),\r\n                            name: \"Description\",\r\n                            value: \"\",  \r\n                            validationRules: { \"required\": false, max: 4000 },\r\n                            config: {\r\n                                rows:3\r\n                            }\r\n                        }\r\n                    ]\r\n                }\r\n            ],\r\n            AnswerTypeData:[],\r\n            SectionData: [{ \r\n                SectionTitle: '',\r\n                IsShowItem:false,\r\n                IsCheckSection:false,\r\n                ItemData:[{\r\n                    Title:'',\r\n                    AnswerType:'',\r\n                    AnswerOption:'',\r\n                    IsItemChcek:false,\r\n                    IsitemAsnwwr:false,\r\n                }] \r\n            }],\r\n            IsAddSection:false,\r\n            isCheckListPreview:false,\r\n            CheckListId:0\r\n        }\r\n    },\r\n    created:async function(){\r\n        var vm =this;\r\n        await vm.GetCheckListStatus();\r\n        await vm.GetModuleName();\r\n        await vm.GetAnswerType();\r\n        await vm.GetIndustryType();\r\n        if(vm.CheckListId>0){\r\n            vm.CheckListId=vm.CheckListId;\r\n            vm.GetCheckListDeatils(vm.CheckListId);\r\n        }\r\n    },\r\n    methods:{\r\n        async GetIndustryType(){  \r\n            var vm =this;          \r\n            DataService.ChecklistGetTemplateList().then((response) => {                \r\n                if (response.data.result.DATA.length > 0) {\r\n                    response.data.result.DATA.forEach(element => {\r\n                        let obj={\r\n                            name:element.name,\r\n                            value:element.id\r\n                        }\r\n                        vm.FormSchema[0].Data[3].config.options.push(obj);\r\n                    })\r\n                    vm.$refs.AssignTagForm.UpdateKeyValue();\r\n                }\r\n            })\r\n        },\r\n        async GetModuleName(){\r\n            var vm =this;\r\n            var url = `id=&moduleName=&type=PHASE_TYPE&search=&refId=`;            \r\n            await DataService.GetDDLData(url).then((response)=>{ \r\n                if (response.status == 200) {\r\n                    if (response.data.DATA != undefined || response.data.DATA != null) {\r\n                        if (response.data.DATA.length > 0) {\r\n                            var ModuleData=response.data.DATA;\r\n                            ModuleData.forEach(element => {\r\n                                let obj={\r\n                                    name:element.name,\r\n                                    value:element.value\r\n                                }\r\n                                vm.FormSchema[0].Data[1].config.options.push(obj);\r\n                            });\r\n                            vm.$refs.AssignTagForm.UpdateKeyValue();\r\n                        }\r\n                    }\r\n                }\r\n            })\r\n        },\r\n        async GetCheckListStatus(){\r\n            var vm =this;\r\n            var url = `id=&moduleName=&type=GLOBAL_STATUS&search=&refId=`;            \r\n            await DataService.GetDDLData(url).then((response)=>{\r\n                if (response.status == 200) {\r\n                    if (response.data.DATA != undefined || response.data.DATA != null) {\r\n                        if (response.data.DATA.length > 0) { \r\n                            var CheckListStatus=response.data.DATA;\r\n                            CheckListStatus.forEach(element => {\r\n                                let obj={\r\n                                    name:element.name,\r\n                                    value:element.value\r\n                                }\r\n                                vm.FormSchema[0].Data[2].config.options.push(obj);\r\n                            });\r\n                            vm.$refs.AssignTagForm.UpdateKeyValue();\r\n                        }\r\n                    }\r\n                }\r\n            })\r\n        },\r\n        async GetAnswerType(){\r\n            var vm =this;\r\n            var url = `id=&moduleName=&type=CHECK_LIST_ANSWER_TYPE&search=&refId=`;            \r\n            await DataService.GetDDLData(url).then((response)=>{\r\n                if (response.status == 200) {\r\n                    if (response.data.DATA != undefined || response.data.DATA != null) {\r\n                        if (response.data.DATA.length > 0) { \r\n                            vm.AnswerTypeData=response.data.DATA;\r\n                        }\r\n                    }\r\n                }\r\n            })\r\n        },\r\n        AddSection() {\r\n            this.SectionData.push({\r\n                SectionTitle: '', \r\n                IsCheckSection:false,               \r\n                ItemData: [{Title:'',\r\n                    AnswerType:'',\r\n                    AnswerOption:'',\r\n                    IsItemChcek:false,\r\n                    IsitemAsnwwr:false}]\r\n            });\r\n        },\r\n        showChildItem(section,index){\r\n            var vm = this;\r\n            section.IsShowItem=true;\r\n        },\r\n        addItem(section, index) {\r\n            section.ItemData.push({\r\n                    Title:'',\r\n                    AnswerType:'',\r\n                    AnswerOption:'',\r\n                    IsItemChcek:false,\r\n                    IsitemAsnwwr:false\r\n                });\r\n        },\r\n        deleteSection(index) {\r\n            var vm=this;\r\n            vm.confirmR(vm.$t(\"ConfirmDelete\"), true, (vm.$t(\"Delete\") + \"  \" + vm.$t(\"Section\")), function () {                \r\n                vm.SectionData.splice(index, 1);\r\n            })            \r\n        },\r\n        deleteItem(section, itemIndex) {\r\n            var vm=this;\r\n            vm.confirmR(vm.$t(\"ConfirmDelete\"), true, (vm.$t(\"Delete\") + \"  \" + vm.$t(\"Item\")), function () {\r\n                section.ItemData.splice(itemIndex, 1);\r\n            })             \r\n        },\r\n        onAnswerTypeChange(event){\r\n            event.IsitemAsnwwr= event.AnswerType == ''?true:false;\r\n        },\r\n        addChild(section, itemIndex) {\r\n            const item = section.ItemData[itemIndex];\r\n            section.ItemData.push({\r\n                Title:'',\r\n                AnswerType:'',\r\n                AnswerOption:'',\r\n                IsItemChcek:false,\r\n                IsitemAsnwwr:false\r\n            });\r\n        },  \r\n        GetCheckListDeatils(value){\r\n            var ths=this;\r\n            var ChechListId=`ChechListId=${value}`;\r\n            DataService.GetCheckListDeatils(ChechListId).then((response)=>{\r\n                if(response.data.result != null){\r\n                    var CheckListData=response.data.result.CheckListData;\r\n                    var ChecListItemData=response.data.result.CheckListDataItems;\r\n                    if(CheckListData.length>0){\r\n                        ths.CheckListId=CheckListData[0].checklist_id;\r\n                        ths.FormSchema[0].Data[0].value=CheckListData[0].checklist_name;\r\n                        ths.FormSchema[0].Data[1].value=CheckListData[0].module_id;\r\n                        ths.FormSchema[0].Data[2].value=CheckListData[0].status_id;\r\n                        ths.FormSchema[0].Data[3].value=CheckListData[0].industry_type_id;\r\n                        ths.FormSchema[1].Data[0].value=CheckListData[0].description;\r\n                    }\r\n                    if(ChecListItemData.length>0){\r\n                        const result = [];\r\n                        ChecListItemData.forEach(item => {\r\n                            let section = result.find(section => section.SectionTitle === item.section_title);\r\n                            if (!section) {\r\n                                section = {\r\n                                    SectionTitle: item.section_title,\r\n                                    IsShowItem: false,\r\n                                    IsCheckSection:false,  \r\n                                    ItemData: []\r\n                                };\r\n                                result.push(section);\r\n                            }\r\n                            section.ItemData.push({\r\n                                Title: item.title,\r\n                                AnswerType: item.answer_type,\r\n                                AnswerOption: item.options,\r\n                                IsItemChcek: false,\r\n                                IsitemAsnwwr:false\r\n                            });\r\n                        })\r\n                        ths.SectionData=result;\r\n                    }\r\n                }\r\n            });\r\n        }, \r\n        CheckSetion(event){\r\n            event.IsCheckSection=event.SectionTitle != ''?false:true;\r\n        },   \r\n        CheckItemSetion(event){\r\n            event.IsItemChcek=event.Title != ''?false:true;\r\n        },     \