Item){\r\n                        var obj = {\r\n                            checklist_id:ths.CheckListId,\r\n                            checkListTitele:ths.FormSchema[0].Data[0].value,\r\n                            ModuleId:ths.FormSchema[0].Data[1].value,\r\n                            Status:ths.FormSchema[0].Data[2].value,\r\n                            Description:ths.FormSchema[1].Data[0].value,\r\n                            IndustryTypeId:ths.FormSchema[0].Data[3].value,\r\n                            ChechListData:ths.SectionData\r\n                        }\r\n                        var jsonObj=JSON.stringify(obj);\r\n                        DataService.SaveCheckList(jsonObj).then(function (response) {                \r\n                            ths.isLoading=false;\r\n                            if(response.data.result.Data.length>0){ \r\n                                if(response.data.result.Data[0].valuess=='INSERT') {\r\n                                    if(ths.CheckListId>0){\r\n                                        ths.ShowAlert(ths.$t('UpdatedSuccess',[ths.$t('CheckList')]),\"success\", true, ths.$t(\"Alert\"));\r\n                                    }else{\r\n                                        ths.ShowAlert(ths.$t('AddedSuccess',[ths.$t('CheckList')]), \"success\", true,  ths.$t(\"Alert\"));\r\n                                    } \r\n                                    ths.CloseCheckList();\r\n                                    ths.$parent.FetchCheckListing();                               \r\n                                }\r\n                                else if(response.data.result.Data[0].valuess=='EXIST') {\r\n                                    ths.ShowAlert(ths.$t(\"RecordAlreadyExists\"), \"warning\", true, ths.$t('Alert'));\r\n                                }\r\n                            }else{\r\n                                ths.ShowAlert(ths.$t(\"UnknownErrorOccur\"), \"failure\", true, ths.$t('Alert'));\r\n