Schema)[1].Data[3].visibility = true;\r\n                (vm.FormSchema)[1].Data[4].visibility = true;\r\n            }            \r\n            if(vm.TaxData.tax_for=='district'){\r\n                (vm.FormSchema)[0].Data[0].value=2024;\r\n                (vm.FormSchema)[1].Data[2].visibility = true;\r\n                (vm.FormSchema)[1].Data[3].visibility = true;\r\n            }\r\n            if(vm.TaxData.tax_for=='state'){\r\n                (vm.FormSchema)[0].Data[0].value=2023;\r\n                (vm.FormSchema)[1].Data[2].visibility = true;\r\n            }     \r\n            (vm.FormSchema)[1].Data[0].value=vm.TaxData.tax_name,\r\n            // (vm.FormSchema)[1].Data[1].value=vm.TaxData.code_id,\r\n            (vm.FormSchema)[1].Data[1].value=vm.TaxData.tax_country,\r\n            vm.OnChangeCountryList(vm.TaxData.tax_country)\r\n            (vm.FormSchema)[1].Data[2].value=vm.TaxData.tax_state,\r\n            vm.OnChangeStateList(vm.TaxData.tax_state)\r\n            (vm.FormSchema)[1].Data[3].value=vm.TaxData.tax_district,\r\n            vm.OnChangeDistrictList(vm.TaxData.tax_district)\r\n            (vm.FormSchema)[1].Data[4].value=vm.TaxData.tax_zipcode,\r\n            (vm.FormSchema)[1].Data[5].value=(vm.TaxData.tax_type=='percent') ? 100:200,\r\n            (vm.FormSchema)[1].Data[6].value=vm.TaxData.tax_rate,\r\n            (vm.FormSchema)[1].Data[7].value=vm.TaxData.status_id,\r\n            (vm.FormSchema)[1].Data[8].value=vm.TaxData.tax_rate.Priority,\r\n            (vm.FormSchema)[2].Data[1].value=vm.TaxData.tax_desc\r\n        }\r\n\r\n    },\r\n    methods: {\r\n        Close: function () {\r\n            this.$parent.AddItem = false;\r\n        },\r\n        GetRadioValue(data, event, getid) {           \r\n            var vm = this;\r\n            (vm.FormSchema)[1].Data[3].visibility = false;\r\n            (vm.FormSchema)[1].Data[4].visibility = false;\r\n            // (vm.FormSchema)[1].Data[5].visibility = false;\r\n\r\n           